const post = $('Load Recent Post Results').first().json
const data = $input.first().json
const platform = post.platform

let metrics = { post_result_id: post.id, platform, external_post_id: post.external_post_id, measured_at: new Date().toISOString() }

if (platform === 'instagram') {
  metrics.likes       = data.like_count || null
  metrics.comments    = data.comments_count || null
  metrics.reach       = data.reach || null
  metrics.impressions = data.impressions || null
  metrics.saves       = data.saved || null
  metrics.shares      = data.shares || null
  if (metrics.reach) metrics.engagement_rate = ((metrics.likes + metrics.comments) / metrics.reach * 100).toFixed(2)
} else if (platform === 'twitter') {
  const pm = data.data?.public_metrics || {}
  metrics.likes    = pm.like_count    || null
  metrics.comments = pm.reply_count   || null
  metrics.shares   = pm.retweet_count || null
  metrics.views    = pm.impression_count || null
}

return [{ json: metrics }]
